class Solution {
    public int kIncreasing(int[] arr, int k) {
        int n = arr.length;
        int[] dp = new int[n];
        for (int i = 0; i < n; i++) {
            dp[i] = arr[i];
        }
        int res = 0;
        for (int i = k; i < n; i++) {
            int j = i - k;
            int maxLen = 1;
            int[] lis = new int[1];
            lis[0] = dp[j];
            for (int t = j - k; t >= 0; t -= k) {
                if (dp[t] <= dp[j]) {
                    int[] temp = lis;
                    lis = new int[maxLen + 1];
                    System.arraycopy(temp, 0, lis, 0, maxLen);
                    lis[maxLen++] = dp[t];
                }
            }
            dp[i] = lis[maxLen - 1];
            res += maxLen - 1;
        }
        return res;
    }
}
